CREATE DATABASE IF NOT EXISTS `rvo` DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci;
SET FOREIGN_KEY_CHECKS = 0;

USE rvo;
-- ----------------------------
-- Table structure for blueprint
-- ----------------------------
DROP TABLE IF EXISTS `blueprint`;
CREATE TABLE `blueprint`  (
  `blueprintID` int NOT NULL AUTO_INCREMENT,
  `background` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '背景图路径',
  `cTime` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `bName` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `width` int NULL DEFAULT NULL,
  `height` int NULL DEFAULT NULL,
  `blueprintJson` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL,
  `replay` varchar(1024) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `hasReplay` tinyint(1) NULL DEFAULT 0,
  `updateTime` datetime NULL DEFAULT CURRENT_TIMESTAMP,
  `numOfPeople` int NULL DEFAULT NULL,
  `duration` int NULL DEFAULT 0,
  `state` smallint NULL DEFAULT 0 COMMENT '状态:0:未提交，1:正在模拟，2:模拟完成',
  `schedule` int NULL DEFAULT 0 COMMENT '进度',
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL,
  `bluprintJson` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL,
  `numOfExits` int NULL DEFAULT 1 COMMENT '出口数量',
  `addr` varchar(1024) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '厂址',
  `lastPeople` int NULL DEFAULT 0,
  `x0` double NULL DEFAULT 0,
  `y0` double NULL DEFAULT 0,
  `x1` double NULL DEFAULT 0,
  `y1` double NULL DEFAULT 0,
  PRIMARY KEY (`blueprintID`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 60 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '蓝图' ROW_FORMAT = Dynamic;

